<template>
  <article class="subteam-tile">
    <h3 class="subteam-title">{{ data.title }}</h3>
    
    <!-- Render the dynamic async component, showing nothing while loading -->
    <component
      v-if="iconComponent"
      :is="iconComponent"
      class="subteam-icon"
      :aria-label="`${data.title} icon`"
      role="img"
      :stroke-width="1.5"
    />
    
    <p class="subteam-description">{{ data.description }}</p>
  </article>
</template>

<script>
import { defineAsyncComponent, markRaw } from "vue";

export default {
  name: "SubteamTile",
  props: {
    data: {
      type: Object,
      required: true
    }
  },
  computed: {
    iconComponent() {
      let key = this.data.lucide;
      
      if (!key) {
        key = "info";
      }

      // 3. Dynamically import the specific icon file on demand
      // markRaw prevents Vue from making the component reactive, saving memory
      return markRaw(
        defineAsyncComponent(() =>
          import(`../../node_modules/lucide-vue-next/dist/esm/icons/${key}.js`)
            .then((m) => m.default)
            .catch(() => {
              // Fail-safe: load CircleHelp if the specified icon doesn't exist
              return import(`../../node_modules/lucide-vue-next/dist/esm/icons/circle-help.js`)
                .then((m) => m.default);
            })
        )
      );
    }
  }
}
</script>

<style lang="scss">
.subteam-tile {
  display: grid;
  grid-template-rows: minmax(4.5rem, auto) 8.5rem auto;
  justify-items: center;
  align-items: center;
  // row-gap: .25rem;
  color: var(--dark);
  flex: 0 1 15rem;
  width: 15rem;
  max-width: 17rem;
  min-width: min-content;

  .subteam-title {
    align-self: end;
    text-align: center;
    color: rgb(103, 103, 103);
    font-family: 'Prompt', sans-serif;
    font-size: 1.5rem;
    font-weight: 800;
    line-height: 1.15;
    margin: 0;
    max-width: 100%;
    text-wrap: balance;
    word-break: normal;
  }

  .subteam-icon {
    width: 6rem;
    height: 6rem;
    // width: clamp(6rem, 9vw, 8rem);
    // height: clamp(6rem, 9vw, 8rem);
    color: var(--regular);
    stroke: currentColor;
    flex: 0 0 auto;
    transition: transform 0.2s ease-in-out;
  }

  .subteam-description {
    text-align: center;
    color: #002f50;
    font-size: 1rem;
    line-height: 1.18;
    margin: 0;
    max-width: 17rem;
    width: 100%;
    word-break: normal;
  }

  &:hover {
    .subteam-icon {
      transform: scale(1.1);
    }
  }
}

@media screen and (max-width: 768px) {
  .subteam-tile {
    grid-template-rows: auto 7rem auto;
    row-gap: 1rem;

    .subteam-title {
      font-size: clamp(1.25rem, 5.6vw, 1.75rem);
      line-height: 1.12;
    }

    .subteam-icon {
      width: clamp(4.75rem, 18vw, 6.25rem);
      height: clamp(4.75rem, 18vw, 6.25rem);
    }

    .subteam-description {
      font-size: clamp(0.82rem, 3.5vw, 1rem);
      line-height: 1.16;
    }
  }
}
</style>